package main

import (
	"html/template"
	"net/http"
)

type Comment struct {
	Username string
	Content   string
}

var comments []Comment

func renderComments(w http.ResponseWriter, r *http.Request) {
	tmpl, _ := template.ParseFiles("comments.html")
	tmpl.Execute(w, comments)
}

func main() {
	comments = []Comment{
		{"John", "This is a comment."},
		{"Jane", "Another comment with formatting! **Bold text**."},
	}

	http.HandleFunc("/comments", renderComments)
	http.ListenAndServe(":8080", nil)
}